  '        _id:       { type: "TEXT", primaryKey: true },',
  '        email:     { type: "TEXT", notNull: true },',
  '        emailHash: { type: "TEXT", notNull: true, unique: true },',
  '        name:      { type: "TEXT" },',
  '        createdAt: { type: "INTEGER", notNull: true },',
  '      },',
  '      sealedFields:   ["email", "name"],',
  '      derivedHashes:  { emailHash: { from: "email" } },',
  '      indexes:        [{ name: "idx_users_created", columns: ["createdAt"] }],',
  '    },',
  '  ],',
  '});</code></pre>',

  '<h3>b.db.from(tableName) — Query builder</h3>',
  '<p>Chainable; every call but the terminal verb returns the same Query for further refinement.</p>',
  '<pre><code class="language-javascript">// Query methods:',
  '//   .where(field, op?, value)              // op-form or shorthand 2-arg',
  '//   .where({ field: value, ... })           // object-form, AND of equalities',
  '//   .select(["col1", "col2"])               // optional projection',
  '//   .orderBy(field, "asc" | "desc")',
  '//   .limit(n).offset(n)',
  '//',
  '// Terminal methods (sync — node:sqlite is synchronous):',
  '//   .first() / .all() / .count()',
  '//   .insertOne(row) / .insertMany(rows)',
  '//   .updateOne(changes) / .updateMany(changes)',
  '//   .deleteOne() / .deleteMany()',
  '//   .stream()                               // → Readable in object mode',
  '',
  'await b.db.from("users").insertOne({',
  '  _id:       "u-42",',
  '  email:     "alice@example.com",   // sealed in transit to disk',
  '  name:      "Alice",                // sealed',
  '  createdAt: Date.now(),',
  '});',
  '// On disk: emailHash = SHA3-512("alice@example.com"); email/name vault-sealed.',
  '',
