  'var alice = b.db.from("users")',
  '  .where({ email: "alice@example.com" })   // → WHERE emailHash = ?',
  '  .first();',
  '// row comes back unsealed: { _id, email, name, ... }</code></pre>',
  '<p>Sealed columns without a derived hash <strong>throw</strong> on <code>where()</code> — every encryption uses a fresh nonce, so a direct ciphertext lookup would always return zero rows. Failing loudly is safer than the silent zero-row trap.</p>',

  '<h3>Other surface</h3>',
